def validate_script(script_source):
    """
    Validate that a script is safe to execute.
    Only allows Painless scripting language with restricted operations.
    """
    if not script_source or not isinstance(script_source, str):
        return False, "Script source must be a non-empty string"

    if len(script_source) > MAX_SCRIPT_LENGTH:
        return False, f"Script exceeds maximum length of {MAX_SCRIPT_LENGTH} characters"

    script_lower = script_source.lower()

    for blocked in BLOCKED_SCRIPT_PATTERNS:
        if blocked.lower() in script_lower:
            return False, f"Script contains blocked pattern: '{blocked}'"

    return True, "Script is valid"


def validate_aggregation_type(agg_type):
    """Validate that the aggregation type is allowed."""
    if agg_type not in ALLOWED_AGGREGATION_TYPES:
        return False, f"Aggregation type '{agg_type}' is not allowed. Allowed types: {ALLOWED_AGGREGATION_TYPES}"
    return True, "Valid aggregation type"


def validate_script_language(language):
    """Validate that only allowed scripting languages are used."""
