def build_query(query_config):
    """Build an Elasticsearch query from configuration."""
    if not query_config:
        return {"match_all": {}}

    allowed_query_types = [
        "match_all", "match", "term", "terms", "range",
        "bool", "exists", "wildcard", "prefix",
    ]

    if isinstance(query_config, dict):
        for key in query_config:
            if key not in allowed_query_types:
                raise ValueError(f"Query type '{key}' is not allowed")

    return query_config


@app.route("/api/aggregate", methods=["POST"])
def execute_aggregation():
    """
    Execute a dynamic aggregation query against Elasticsearch.

    Expected JSON body:
    {
        "index": "analytics_data",  (optional, defaults to ES_INDEX)
        "query": { ... },           (optional, Elasticsearch query)
        "aggregations": {
            "agg_name": {
                "type": "sum|avg|scripted_metric|bucket_script|...",
                "field": "field_name",   (for standard aggs)
                "script": "...",         (for script-based aggs)
                "params": { ... },       (optional script params)
                ...
            }
        },
        "size": 0                   (optional, number of hits to return)
    }
    """
    try:
        req_data = request.get_json()
        if not req_data:
            return jsonify({"error": "Request body must be valid JSON"}), 400

        index = req_data.get("index", ES_INDEX)
        if not isinstance(index, str) or not index.replace("_", "").replace("-", "").isalnum():
            return jsonify({"error": "Invalid index name"}), 400

        aggregations_config = req_data.get("aggregations", {})
        if not aggregations_config:
            return jsonify({"error": "No aggregations specified"}), 400

        if len(aggregations_config) > 20:
            return jsonify({"error": "Too many aggregations (max 20)"}), 400

        query = build_query(req_data.get("query"))

        aggs = {}
        for agg_name, agg_config in aggregations_config.items():
            if not isinstance(agg_name, str) or not agg_name.replace("_", "").isalnum():
                return jsonify({"error": f"Invalid aggregation name: {agg_name}"}), 400
            aggs[agg_name] = build_aggregation(agg_name, agg_config)

        size = min(int(req_data.get("size", 0)), 100)

        es_body = {"query": query, "aggs": aggs, "size": size}

        logger.info(f"Executing aggregation on index '{index}': {json.dumps(es_body, indent=2)}")

        result = es.search(index=index, body=es_body)

        response = {
            "took": result.get("took"),
            "total_hits": result.get("hits", {}).get("total", {}).get("value", 0),
            "aggregations": result.get("aggregations", {}),
        }

        if size > 0:
            response["hits"] = [hit["_source"] for hit in result.get("hits", {}).get("hits", [])]

        return jsonify(response), 200

    except ValueError as e:
        logger.warning(f"Validation error: {str(e)}")
        return jsonify({"error": f"Validation error: {str(e)}"}), 400
    except Exception as e:
        logger.error(f"Error executing aggregation: {str(e)}")
        return jsonify({"error": f"Execution error: {str(e)}"}), 500


